// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader !== undefined ? headers[apiKeyHeader] : '';
const expectedKey = $env.LANGFLOW_API_KEY;

// Timing-safe comparison - prevents timing attacks on API key
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 256;
  if (a.length > MAX_LEN || b.length > MAX_LEN) return false;

  let result = 0;
  // Constant-time comparison: always iterate MAX_LEN, use 0 for out-of-bounds
  for (let i = 0; i < MAX_LEN; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  // Include length check in constant-time result
  result |= (a.length === b.length) ? 0 : 1;
  return result === 0;
}

if (expectedKey && !timingSafeEqual(providedKey, expectedKey)) {
  throw new Error('Authentication failed');
}

const input = $input.first().json || {};
const flowId = input.flowId || '';
const input_value = input.input_value || '';
const input_type = input.input_type || 'chat';
const output_type = input.output_type || 'chat';
const components = input.components || {};
const stream = input.stream || false;

// === FLOW_ID VALIDATION ===
if (!flowId) {
  throw new Error('Missing required field: flowId');
}
if (typeof flowId !== 'string') {
  throw new Error('Invalid flowId: must be a string');
}
if (flowId.length > 100) {
  throw new Error('flowId too long: max 100 characters');
}

// === INPUT_VALUE VALIDATION ===
if (!input_value) {
  throw new Error('Missing required field: input_value');
}
if (typeof input_value !== 'string') {
  throw new Error('Invalid input_value: must be a string');
}
if (input_value.length > 32768) {
  throw new Error('input_value too long: max 32768 characters');
}

// === INPUT_TYPE VALIDATION ===
const validInputTypes = ['chat', 'text', 'document'];
if (!validInputTypes.includes(input_type)) {
  throw new Error('Invalid input_type: must be one of ' + validInputTypes.join(', '));
}

// === OUTPUT_TYPE VALIDATION ===
const validOutputTypes = ['chat', 'text', 'debug'];
if (!validOutputTypes.includes(output_type)) {
  throw new Error('Invalid output_type: must be one of ' + validOutputTypes.join(', '));
}

// === STREAM VALIDATION ===
if (typeof stream !== 'boolean') {
  throw new Error('Invalid stream: must be a boolean');
}

// === COMPONENTS VALIDATION ===
if (components && typeof components !== 'object') {
  throw new Error('Invalid components: must be a JSON object');
}

// === CHANNEL VALIDATION ===
const channelRaw = (input.channel || 'general').replace(/^#+/, '').replace(/[<>@&]/g, '').slice(0, 100);
if (!channelRaw.match(/^[a-zA-Z0-9_-]+$/)) {
  throw new Error('Invalid channel: must be alphanumeric, dash, or underscore only');
}

return [{
  json: {
    flowId: flowId,
    input_value: input_value,
    input_type: input_type,
    output_type: output_type,
    components: components,
    stream: stream,
    channel: channelRaw
  }
}];

