// Process Langflow response
const body = $input.first().json || {};
const webhookInput = $input.all()[1]?.json || {};

// Langflow returns output in different formats depending on the flow
const outputs = body.outputs || body.output || [];
const text = outputs[0]?.outputs?.message?.text || outputs[0]?.outputs?.output || body.results?.output || body.output || '';
const latency = body.latency || body.time || 0;
const flowId = body.id || $('Validate Input').first().json.flowId;

return [{
  json: {
    success: !!text,
    text: text,
    latency: latency,
    flowId: flowId,
    channel: webhookInput.channel || 'general',
    timestamp: new Date().toISOString()
  }
}];
